595	/**
596	 * @typedef {Object} FillMaskSingle
597	 * @property {string} sequence The corresponding input with the mask token prediction.
598	 * @property {number} score The corresponding probability.
599	 * @property {number} token The predicted token id (to replace the masked one).
600	 * @property {string} token_str The predicted token (to replace the masked one).
601	 * @typedef {FillMaskSingle[]} FillMaskOutput
602	 *
603	 * @typedef {Object} FillMaskPipelineOptions Parameters specific to fill mask pipelines.
604	 * @property {number} [top_k=5] When passed, overrides the number of predictions to return.
605	 *
606	 * @callback FillMaskPipelineCallback Fill the masked token in the text(s) given as inputs.
607	 * @param {string|string[]} texts One or several texts (or one list of prompts) with masked tokens.
608	 * @param {FillMaskPipelineOptions} [options] The options to use for masked language modelling.
609	 * @returns {Promise<FillMaskOutput|FillMaskOutput[]>} An array of objects containing the score, predicted token, predicted token string,
610	 * and the sequence with the predicted token filled in, or an array of such arrays (one for each input text).
611	 * If only one input text is given, the output will be an array of objects.
612	 * @throws {Error} When the mask token is not found in the input text.
613	 *
614	 * @typedef {TextPipelineConstructorArgs & FillMaskPipelineCallback & Disposable} FillMaskPipelineType
615	 */
616	
617	/**
618	 * Masked language modeling prediction pipeline using any `ModelWithLMHead`.
619	 *
620	 * **Example:** Perform masked language modelling (a.k.a. "fill-mask") with `Xenova/bert-base-uncased`.
621	 * ```javascript
622	 * const unmasker = await pipeline('fill-mask', 'Xenova/bert-base-cased');
623	 * const output = await unmasker('The goal of life is [MASK].');
624	 * // [
625	 * //   { token_str: 'survival', score: 0.06137419492006302, token: 8115, sequence: 'The goal of life is survival.' },
626	 * //   { token_str: 'love', score: 0.03902450203895569, token: 1567, sequence: 'The goal of life is love.' },
627	 * //   { token_str: 'happiness', score: 0.03253183513879776, token: 9266, sequence: 'The goal of life is happiness.' },
628	 * //   { token_str: 'freedom', score: 0.018736306577920914, token: 4438, sequence: 'The goal of life is freedom.' },
629	 * //   { token_str: 'life', score: 0.01859794743359089, token: 1297, sequence: 'The goal of life is life.' }
630	 * // ]
631	 * ```
632	 *
633	 * **Example:** Perform masked language modelling (a.k.a. "fill-mask") with `Xenova/bert-base-cased` (and return top result).
634	 * ```javascript
635	 * const unmasker = await pipeline('fill-mask', 'Xenova/bert-base-cased');
636	 * const output = await unmasker('The Milky Way is a [MASK] galaxy.', { top_k: 1 });
637	 * // [{ token_str: 'spiral', score: 0.6299987435340881, token: 14061, sequence: 'The Milky Way is a spiral galaxy.' }]
638	 * ```
639	 */
640	export class FillMaskPipeline extends (/** @type {new (options: TextPipelineConstructorArgs) => FillMaskPipelineType} */ (Pipeline)) {
641	
642	    /**
643	     * Create a new FillMaskPipeline.
644	     * @param {TextPipelineConstructorArgs} options An object used to instantiate the pipeline.
645	     */
646	    constructor(options) {
647	        super(options);
648	    }
649	
650	    /** @type {FillMaskPipelineCallback} */
651	    async _call(texts, {
652	        top_k = 5
653	    } = {}) {
654	
655	        // Run tokenization
656	        const model_inputs = this.tokenizer(texts, {
657	            padding: true,
658	            truncation: true,
659	        });
660	
661	        // Run model
662	        const { logits } = await this.model(model_inputs)
663	
664	        const toReturn = [];
665	
666	        /** @type {bigint[][]} */
667	        const input_ids = model_inputs.input_ids.tolist();
668	        for (let i = 0; i < input_ids.length; ++i) {
669	            const ids = input_ids[i];
670	            const mask_token_index = ids.findIndex(x =>
671	                // We use == to match bigint with number
672	                // @ts-ignore
673	                x == this.tokenizer.mask_token_id
674	            );
675	            if (mask_token_index === -1) {
676	                throw Error(`Mask token (${this.tokenizer.mask_token}) not found in text.`)
677	            }
678	            const itemLogits = logits[i][mask_token_index];
679	
680	            const scores = await topk(new Tensor(
681	                'float32',
682	                softmax(itemLogits.data),
683	                itemLogits.dims,
684	            ), top_k);
685	            const values = scores[0].tolist();
686	            const indices = scores[1].tolist();
687	
688	            toReturn.push(indices.map((x, i) => {
689	                const sequence = ids.slice();
690	                sequence[mask_token_index] = x;
691	
692	                return {
693	                    score: values[i],
694	                    token: Number(x),
695	                    token_str: this.tokenizer.decode([x]),
696	                    sequence: this.tokenizer.decode(sequence, { skip_special_tokens: true }),
697	                }
698	            }));
699	        }

