4918	                    const offset = text_len + st_idx;
4919	                    const grid_size = llm_grid_t * llm_grid_h * llm_grid_w;
4920	                    const t_index = Array.from({ length: grid_size }, (_, i) => offset + Math.floor(i / (llm_grid_h * llm_grid_w)))
4921	                    const h_index = Array.from({ length: grid_size }, (_, i) => offset + Math.floor(i / llm_grid_w) % llm_grid_h)
