**Location:** `/src/utils/image.js` (lines 77-149)

`RawImage` handles multiple image input types:
```javascript
export class RawImage {
    static async read(input) {
        if (input instanceof RawImage) return input;
        else if (typeof input === 'string' || input instanceof URL) return await this.fromURL(input);
        else if (input instanceof Blob) return await this.fromBlob(input);
        else if (input instanceof HTMLCanvasElement || input instanceof OffscreenCanvas)
            return this.fromCanvas(input);
        else throw new Error(`Unsupported input type: ${typeof input}`);
    }
}
```

